it("should show result summary with match count", async () => {
  const scrollIntoViewMock = jest.fn();
  window.HTMLElement.prototype.scrollIntoView = scrollIntoViewMock;

  API.setElements([
    API.createElement({ type: "text", text: "hello world" }),
    API.createElement({ type: "text", text: "hello again" }),
    API.createElement({ type: "text", text: "goodbye" }),
  ]);

  Keyboard.withModifierKeys({ ctrl: true }, () => {
    Keyboard.keyPress(KEYS.F);
  });

  const searchInput = await querySearchInput();
  updateTextEditor(searchInput, "hello");

  await waitFor(() => {
    const summary =
      h.app.excalidrawContainerValue.container?.querySelector(
        "[data-testid='search-summary']",
      );
    expect(summary).not.toBeNull();
    expect(summary!.textContent).toMatch(/2\s.*results/);
  });
});

it("should show single result text for one match", async () => {
  const scrollIntoViewMock = jest.fn();
  window.HTMLElement.prototype.scrollIntoView = scrollIntoViewMock;

  API.setElements([
    API.createElement({ type: "text", text: "unique" }),
    API.createElement({ type: "text", text: "other" }),
  ]);

  Keyboard.withModifierKeys({ ctrl: true }, () => {
    Keyboard.keyPress(KEYS.F);
  });

  const searchInput = await querySearchInput();
  updateTextEditor(searchInput, "unique");

  await waitFor(() => {
    const summary =
      h.app.excalidrawContainerValue.container?.querySelector(
        "[data-testid='search-summary']",
      );
    expect(summary).not.toBeNull();
    expect(summary!.textContent).toMatch(/1\s.*result/);
    // should say "result" not "results"
    expect(summary!.textContent).not.toMatch(/results/);
  });
});

it("should show no-matches empty state for non-matching query", async () => {
  API.setElements([
    API.createElement({ type: "text", text: "hello world" }),
  ]);

  Keyboard.withModifierKeys({ ctrl: true }, () => {
    Keyboard.keyPress(KEYS.F);
  });

  const searchInput = await querySearchInput();
  updateTextEditor(searchInput, "zzzznotfound");

  await waitFor(() => {
    const emptyState =
      h.app.excalidrawContainerValue.container?.querySelector(
        "[data-testid='search-empty']",
      );
    expect(emptyState).not.toBeNull();
    expect(emptyState!.textContent).toBe("No matches found...");
  });

  // summary should not be visible
  const summary =
    h.app.excalidrawContainerValue.container?.querySelector(
      "[data-testid='search-summary']",
    );
  expect(summary).toBeNull();
});

it("should not show empty state when search field is cleared", async () => {
  API.setElements([
    API.createElement({ type: "text", text: "hello world" }),
  ]);

  Keyboard.withModifierKeys({ ctrl: true }, () => {
    Keyboard.keyPress(KEYS.F);
  });

  const searchInput = await querySearchInput();
  updateTextEditor(searchInput, "zzzznotfound");

  await waitFor(() => {
    const emptyState =
      h.app.excalidrawContainerValue.container?.querySelector(
        "[data-testid='search-empty']",
      );
    expect(emptyState).not.toBeNull();
  });

  // clear the input
  updateTextEditor(searchInput, "");

  await waitFor(() => {
    const emptyState =
      h.app.excalidrawContainerValue.container?.querySelector(
        "[data-testid='search-empty']",
      );
    expect(emptyState).toBeNull();
  });

  const summary =
    h.app.excalidrawContainerValue.container?.querySelector(
      "[data-testid='search-summary']",
    );
  expect(summary).toBeNull();
});

it("should preserve keyboard navigation after summary is displayed", async () => {
  const scrollIntoViewMock = jest.fn();
  window.HTMLElement.prototype.scrollIntoView = scrollIntoViewMock;

  API.setElements([
    API.createElement({ type: "text", text: "apple pie" }),
    API.createElement({ type: "text", text: "apple cake" }),
    API.createElement({ type: "text", text: "apple tart" }),
  ]);

  Keyboard.withModifierKeys({ ctrl: true }, () => {
    Keyboard.keyPress(KEYS.F);
  });

  const searchInput = await querySearchInput();
  updateTextEditor(searchInput, "apple");

  await waitFor(() => {
    expect(h.app.state.searchMatches?.matches.length).toBe(3);
  });

  // cycle with Enter
  Keyboard.keyPress(KEYS.ENTER, searchInput);
  await waitFor(() => {
    const summary =
      h.app.excalidrawContainerValue.container?.querySelector(
        "[data-testid='search-summary']",
      );
    expect(summary).not.toBeNull();
    expect(summary!.textContent).toMatch(/2\s*\/\s*3\s.*results/);
  });

  // Arrow down
  Keyboard.keyPress(KEYS.ARROW_DOWN, searchInput);
  await waitFor(() => {
    const summary =
      h.app.excalidrawContainerValue.container?.querySelector(
        "[data-testid='search-summary']",
      );
    expect(summary!.textContent).toMatch(/3\s*\/\s*3\s.*results/);
  });

  // Arrow up wraps around
  Keyboard.keyPress(KEYS.ARROW_UP, searchInput);
  await waitFor(() => {
    const summary =
      h.app.excalidrawContainerValue.container?.querySelector(
        "[data-testid='search-summary']",
      );
    expect(summary!.textContent).toMatch(/2\s*\/\s*3\s.*results/);
  });
});

